export interface CowParameters {
  weight: number; // kg
  milkProduction: number; // kg/day
  fatPercentage: number; // %
  pregnancyMonth: number; // 0-9
  growthRate: number; // kg/day (heifers)
  bcsChange: number; // -1 to +1 (loss/gain)
  lactationStage: 'early' | 'mid' | 'late';
}

export interface Nutrients {
  me: number; // Metabolizable Energy (Mcal)
  cp: number; // Crude Protein (g)
  ca: number; // Calcium (g)
  p: number; // Phosphorus (g)
}

export interface FeedIngredient {
  id: string;
  name: string;
  type: 'concentrate' | 'forage';
  dm: number; // Dry Matter %
  me: number; // Mcal/kg DM
  cp: number; // % DM
  ca: number; // % DM
  p: number; // % DM
}

export interface RationItem {
  ingredientId: string;
  amount: number; // kg as fed
  isPercentage?: boolean; // For concentrate mix definition
}

export interface ConcentrateMix {
  ingredients: RationItem[];
  totalMixAmountFed: number; // kg fed to cow
}

export interface ForageRation {
  ingredients: RationItem[];
}

export enum Page {
  NEEDS = 'NEEDS',
  FEED = 'FEED',
  COMPARE = 'COMPARE',
  HEALTH = 'HEALTH'
}

import { CowParameters, Nutrients, RationItem, FeedIngredient } from '../types';
import { FEED_DATABASE } from '../constants';

export const calculateRequirements = (params: CowParameters): Nutrients => {
  let me = 0;
  let cp = 0;
  let ca = 0;
  let p = 0;

  const w075 = Math.pow(params.weight, 0.75);

  // 1. Maintenance
  // Simplified NRC: ME approx 0.08 Mcal/kg BW^0.75
  const meMaint = 0.08 * w075;
  const cpMaint = 4.0 * w075; // Approx g CP
  const caMaint = 0.0154 * params.weight;
  const pMaint = 0.0125 * params.weight; // Simplified

  me += meMaint;
  cp += cpMaint;
  ca += caMaint;
  p += pMaint;

  // 2. Milk Production
  // ME (Mcal/kg milk) = 0.36 + 0.096 * Fat%
  const energyPerKgMilk = 0.36 + (0.096 * params.fatPercentage);
  me += params.milkProduction * energyPerKgMilk;

  // CP approx 85g per kg milk (varies)
  cp += params.milkProduction * 90;

  ca += params.milkProduction * 1.22;
  p += params.milkProduction * 0.9;

  // 3. Pregnancy (Last 3 months significant)
  if (params.pregnancyMonth > 6) {
    const pregFactor = (params.pregnancyMonth - 6) * 0.15; // Escalating factor
    me += 3 * pregFactor; // Add Mcal
    cp += 100 * pregFactor;
    ca += 8 * pregFactor;
    p += 5 * pregFactor;
  }

  // 4. Growth (First calf heifers)
  if (params.growthRate > 0) {
     me += 3 * params.growthRate;
     cp += 250 * params.growthRate;
     ca += 20 * params.growthRate;
     p += 10 * params.growthRate;
  }

  // 5. Body Condition Change (Loss adds energy, Gain requires energy)
  // Gain 1kg body tissue ~ 5 Mcal ME required. Loss 1kg provides ~ 4 Mcal.
  // Assuming 'bcsChange' is normalized score change, simplistic conversion to KG roughly
  // 1 BCS unit (1-5 scale) ~ 50-60kg. 
  // Here we use simplified daily loss/gain logic provided by user?
  // Let's assume input is daily weight change for BCS adjustment.
  // If user inputs score change over season, we might need complex logic.
  // For this demo, let's treat bcsChange as "Target Weight Change kg/day" implied.

  // If bcsChange is positive (Gain needed)
  if (params.bcsChange > 0) {
      me += 5.5 * params.bcsChange; // Cost to add weight
      cp += 50 * params.bcsChange; 
  } else if (params.bcsChange < 0) {
      // Mobilizing reserves
      me += 4.5 * params.bcsChange; // This reduces requirement (adds negative value)
      // Protein mobilization is less efficient to calc, usually ignored for safety or small credit
  }

  return {
    me: parseFloat(me.toFixed(2)),
    cp: Math.round(cp),
    ca: Math.round(ca),
    p: Math.round(p)
  };
};

export const calculateSupplied = (
  concentrateMix: RationItem[], 
  concentrateAmountFed: number, 
  forages: RationItem[]
): Nutrients & { totalDM: number, concentrateAnalysis: Nutrients } => {

  let totalME = 0;
  let totalCP = 0;
  let totalCa = 0;
  let totalP = 0;
  let totalDM = 0;

  // 1. Calculate Concentrate Mix Analysis (per 1kg of mix)
  // Normalize percentages first in case user didn't sum to 100
  const totalParts = concentrateMix.reduce((acc, item) => acc + item.amount, 0);

  let mixME = 0, mixCP = 0, mixCa = 0, mixP = 0;

  if (totalParts > 0) {
    concentrateMix.forEach(item => {
        const feed = FEED_DATABASE.find(f => f.id === item.ingredientId);
        if (feed) {
            const ratio = item.amount / totalParts; // The portion of this ingredient in 1kg of mix
            // Convert values from DM basis to As Fed for the mix calculation if needed?
            // Usually formulations are on DM basis, but farmers mix As Fed.
            // Let's assume input percentages are "As Fed" weights.

            const dmFactor = feed.dm / 100;

            // Contribution to 1kg of As Fed Mix
            // ME is usually Mcal/kg DM. 
            // 1kg As Fed contains (dmFactor) kg DM.
            mixME += (feed.me * dmFactor) * ratio;
            mixCP += (feed.cp * 10 * dmFactor) * ratio; // CP % to g/kg
            mixCa += (feed.ca * 10 * dmFactor) * ratio;
            mixP += (feed.p * 10 * dmFactor) * ratio;
        }
    });
  }

  const concAnalysis = { me: mixME, cp: mixCP, ca: mixCa, p: mixP };

  // 2. Add Concentrate Supplied to Total
  // concentrateAmountFed is As Fed kg
  // We already calculated nutrient per 1kg As Fed mix above
  totalME += mixME * concentrateAmountFed;
  totalCP += mixCP * concentrateAmountFed;
  totalCa += mixCa * concentrateAmountFed;
  totalP += mixP * concentrateAmountFed;

  // Estimate DM of mix
  const mixDM = concentrateMix.reduce((acc, item) => {
      const feed = FEED_DATABASE.find(f => f.id === item.ingredientId);
      return acc + (feed ? (feed.dm / 100) * (item.amount/totalParts) : 0);
  }, 0);
  totalDM += mixDM * concentrateAmountFed;

  // 3. Add Forages
  forages.forEach(item => {
      const feed = FEED_DATABASE.find(f => f.id === item.ingredientId);
      if (feed && item.amount > 0) {
          const dmFactor = feed.dm / 100;
          const kgDM = item.amount * dmFactor;

          totalME += feed.me * kgDM;
          totalCP += feed.cp * 10 * kgDM; // % * 10 = g/kg
          totalCa += feed.ca * 10 * kgDM;
          totalP += feed.p * 10 * kgDM;
          totalDM += kgDM;
      }
  });

  return {
    me: parseFloat(totalME.toFixed(2)),
    cp: Math.round(totalCP),
    ca: Math.round(totalCa),
    p: Math.round(totalP),
    totalDM: parseFloat(totalDM.toFixed(2)),
    concentrateAnalysis: {
        me: parseFloat(mixME.toFixed(2)),
        cp: Math.round(mixCP),
        ca: Math.round(mixCa),
        p: Math.round(mixP)
    }
  };
};

import { GoogleGenAI } from "@google/genai";
import { Nutrients, CowParameters } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const predictMetabolicHealth = async (
  cowParams: CowParameters,
  needs: Nutrients,
  supplied: Nutrients,
  forageToConcRatio: number
): Promise<string> => {
  const model = "gemini-3-flash-preview";

  const prompt = `
    أنت طبيب بيطري وخبير تغذية أبقار. قم بتحليل هذه العليقة وتوقع الأمراض الاستقلابية المحتملة.

    بيانات البقرة:
    الوزن: ${cowParams.weight} كغ
    انتاج الحليب: ${cowParams.milkProduction} كغ
    الحمل: شهر ${cowParams.pregnancyMonth}

    الاحتياجات مقابل المقدم:
    الطاقة (Mcal): المقدم ${supplied.me} / المطلوب ${needs.me}
    البروتين (g): المقدم ${supplied.cp} / المطلوب ${needs.cp}
    الكالسيوم (g): المقدم ${supplied.ca} / المطلوب ${needs.ca}
    الفوسفور (g): المقدم ${supplied.p} / المطلوب ${needs.p}

    نسبة العلف المالك للمركز تقريباً: ${forageToConcRatio.toFixed(2)}

    المطلوب:
    1. هل هناك خطر للإصابة بالحماض الكرشي (Acidosis)؟ لماذا؟
    2. هل هناك خطر للكيتوزيس (Ketosis)؟
    3. هل هناك خطر لحمى الحليب (Milk Fever)؟
    4. نصيحة قصيرة واحدة لتحسين العليقة.

    أجب باللغة العربية بأسلوب علمي ومختصر.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
    });
    return response.text || "لم يتمكن النظام من توليد تحليل حالياً.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "عذراً، حدث خطأ أثناء الاتصال بخدمة الذكاء الاصطناعي.";
  }
};

