import React, { useMemo } from 'react';
import { RationItem, Nutrients } from '../types';
import { FEED_DATABASE } from '../constants';

interface FeedFormProps {
  concentrateMix: RationItem[];
  setConcentrateMix: (items: RationItem[]) => void;
  concentrateFedAmount: number;
  setConcentrateFedAmount: (n: number) => void;
  forages: RationItem[];
  setForages: (items: RationItem[]) => void;
  mixAnalysis: Nutrients;
}

const FeedForm: React.FC<FeedFormProps> = ({
  concentrateMix,
  setConcentrateMix,
  concentrateFedAmount,
  setConcentrateFedAmount,
  forages,
  setForages,
  mixAnalysis
}) => {

  const concentrateOptions = FEED_DATABASE.filter(f => f.type === 'concentrate');
  const forageOptions = FEED_DATABASE.filter(f => f.type === 'forage');

  const updateMixItem = (id: string, amount: number) => {
    const existing = concentrateMix.find(i => i.ingredientId === id);
    if (existing) {
      if (amount <= 0) {
        setConcentrateMix(concentrateMix.filter(i => i.ingredientId !== id));
      } else {
        setConcentrateMix(concentrateMix.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setConcentrateMix([...concentrateMix, { ingredientId: id, amount }]);
    }
  };

  const updateForageItem = (id: string, amount: number) => {
    const existing = forages.find(i => i.ingredientId === id);
    if (existing) {
       if (amount <= 0) {
        setForages(forages.filter(i => i.ingredientId !== id));
      } else {
        setForages(forages.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setForages([...forages, { ingredientId: id, amount }]);
    }
  };

  const totalMixPercentage = useMemo(() => 
    concentrateMix.reduce((acc, curr) => acc + curr.amount, 0), [concentrateMix]);

  return (
    <div className="space-y-8">

      {/* 1. Concentrate Mix Definition */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden border border-slate-200">
        <div className="bg-blue-50 px-6 py-4 border-b border-blue-100">
           <h2 className="text-xl font-bold text-blue-800">1. تركيب الخلطة المركزة (النسب المئوية)</h2>
           <p className="text-sm text-blue-600">حدد مكونات العلف المركز ونسبها (المجموع يفضل أن يكون 100% أو 1000 كغ)</p>
        </div>

        <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {concentrateOptions.map(feed => {
            const currentVal = concentrateMix.find(i => i.ingredientId === feed.id)?.amount || '';
            return (
              <div key={feed.id} className="flex items-center gap-2">
                 <label className="text-sm font-medium w-1/2 text-slate-700">{feed.name}</label>
                 <div className="relative w-1/2">
                    <input 
                      type="number"
                      min="0"
                      value={currentVal}
                      onChange={(e) => updateMixItem(feed.id, parseFloat(e.target.value) || 0)}
                      className="w-full p-2 pr-8 border rounded focus:ring-2 focus:ring-blue-500 outline-none text-left ltr"
                    />
                    <span className="absolute right-2 top-2 text-slate-400 text-xs">%</span>
                 </div>
              </div>
            );
          })}
        </div>
        <div className="bg-slate-50 px-6 py-3 border-t flex justify-between items-center">
            <span className="font-bold text-slate-700">المجموع الحالي للنسب:</span>
            <span className={`font-bold px-3 py-1 rounded ${Math.abs(totalMixPercentage - 100) < 0.1 ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                {totalMixPercentage}%
            </span>
        </div>
      </div>

      {/* Mix Analysis Result */}
      <div className="bg-blue-600 text-white rounded-xl p-6 shadow-lg">
          <h3 className="font-bold mb-4">محتوى الخلطة المركزة (لكل 1 كغ علف):</h3>
          <div className="grid grid-cols-4 gap-4 text-center">
              <div>
                  <div className="text-2xl font-bold">{mixAnalysis.me}</div>
                  <div className="text-xs opacity-80">Mcal طاقة</div>
              </div>
              <div>
                  <div className="text-2xl font-bold">{(mixAnalysis.cp / 10).toFixed(1)}%</div>
                  <div className="text-xs opacity-80">بروتين خام</div>
              </div>
              <div>
                  <div className="text-2xl font-bold">{(mixAnalysis.ca / 10).toFixed(2)}%</div>
                  <div className="text-xs opacity-80">كالسيوم</div>
              </div>
               <div>
                  <div className="text-2xl font-bold">{(mixAnalysis.p / 10).toFixed(2)}%</div>
                  <div className="text-xs opacity-80">فوسفور</div>
              </div>
          </div>
      </div>

      {/* 2. Amount Fed */}
      <div className="bg-white rounded-xl shadow-md p-6 border border-slate-200">
         <h2 className="text-xl font-bold text-slate-800 mb-4 border-b pb-2">2. كميات العلف المقدمة للبقرة (يومياً)</h2>

         <div className="mb-6">
            <label className="block text-lg font-medium text-blue-700 mb-2">كمية العلف المركز (من الخلطة السابقة)</label>
            <div className="flex items-center gap-2 max-w-xs">
                <input 
                    type="number" 
                    value={concentrateFedAmount}
                    onChange={(e) => setConcentrateFedAmount(parseFloat(e.target.value) || 0)}
                    className="w-full p-3 border-2 border-blue-200 rounded-lg text-lg focus:border-blue-500 focus:outline-none"
                />
                <span className="font-bold text-slate-600">كغ</span>
            </div>
         </div>

         <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-4">
             <div className="col-span-full font-medium text-emerald-700 mb-2">الأعلاف المالئة (خشنة):</div>
             {forageOptions.map(feed => {
                 const currentVal = forages.find(i => i.ingredientId === feed.id)?.amount || '';
                 return (
                    <div key={feed.id} className="flex items-center gap-4 p-2 hover:bg-slate-50 rounded">
                        <label className="text-sm font-medium w-1/3 text-slate-700">{feed.name}</label>
                        <div className="relative flex-1">
                            <input 
                            type="number"
                            min="0"
                            value={currentVal}
                            onChange={(e) => updateForageItem(feed.id, parseFloat(e.target.value) || 0)}
                            className="w-full p-2 pl-10 border rounded focus:ring-2 focus:ring-emerald-500 outline-none"
                            />
                            <span className="absolute left-3 top-2.5 text-slate-400 text-sm">كغ</span>
                        </div>
                    </div>
                 );
             })}
         </div>
      </div>

    </div>
  );
};

export default FeedForm;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';
import { Nutrients } from '../types';

interface ComparisonProps {
  needs: Nutrients;
  supplied: Nutrients;
  totalDM: number;
}

const Comparison: React.FC<ComparisonProps> = ({ needs, supplied, totalDM }) => {

  const data = [
    { name: 'الطاقة (Mcal)', required: needs.me, supplied: supplied.me, unit: 'Mcal' },
    { name: 'البروتين (g/10)', required: Math.round(needs.cp / 10), supplied: Math.round(supplied.cp / 10), unit: 'x10 g' }, // Scaled for chart visibility
    { name: 'الكالسيوم (g)', required: needs.ca, supplied: supplied.ca, unit: 'g' },
    { name: 'الفوسفور (g)', required: needs.p, supplied: supplied.p, unit: 'g' },
  ];

  const getStatusColor = (req: number, sup: number) => {
    const diff = ((sup - req) / req) * 100;
    if (diff < -10) return 'text-red-600 bg-red-50';
    if (diff > 20) return 'text-yellow-600 bg-yellow-50'; // Warning overfeeding
    return 'text-green-600 bg-green-50';
  };

  const getStatusText = (req: number, sup: number) => {
      const diff = ((sup - req) / req) * 100;
      if (diff < -10) return `نقص (${Math.abs(Math.round(diff))}%)`;
      if (diff > 20) return `زائد (${Math.round(diff)}%)`;
      return 'متوازن';
  };

  return (
    <div className="space-y-8">
      <div className="bg-white p-6 rounded-xl shadow-md border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-6">مقارنة الاحتياجات مع المقدم</h2>

        {/* Table View */}
        <div className="overflow-x-auto mb-8">
            <table className="w-full text-sm text-right text-slate-600">
                <thead className="text-xs text-slate-700 uppercase bg-slate-100">
                    <tr>
                        <th className="px-6 py-3 rounded-r-lg">العنصر الغذائي</th>
                        <th className="px-6 py-3">الاحتياجات المقدرة</th>
                        <th className="px-6 py-3">المقدم في العليقة</th>
                        <th className="px-6 py-3">الفرق</th>
                        <th className="px-6 py-3 rounded-l-lg">الحالة</th>
                    </tr>
                </thead>
                <tbody>
                    <tr className="bg-white border-b">
                        <td className="px-6 py-4 font-medium text-slate-900">الطاقة الاستقلابية (ME)</td>
                        <td className="px-6 py-4">{needs.me} Mcal</td>
                        <td className="px-6 py-4">{supplied.me} Mcal</td>
                        <td className="px-6 py-4 ltr text-right">{(supplied.me - needs.me).toFixed(2)}</td>
                        <td className="px-6 py-4">
                            <span className={`px-2 py-1 rounded text-xs font-bold ${getStatusColor(needs.me, supplied.me)}`}>
                                {getStatusText(needs.me, supplied.me)}
                            </span>
                        </td>
                    </tr>
                    <tr className="bg-white border-b">
                        <td className="px-6 py-4 font-medium text-slate-900">البروتين الخام (CP)</td>
                        <td className="px-6 py-4">{needs.cp} g</td>
                        <td className="px-6 py-4">{supplied.cp} g</td>
                         <td className="px-6 py-4 ltr text-right">{supplied.cp - needs.cp}</td>
                        <td className="px-6 py-4">
                            <span className={`px-2 py-1 rounded text-xs font-bold ${getStatusColor(needs.cp, supplied.cp)}`}>
                                {getStatusText(needs.cp, supplied.cp)}
                            </span>
                        </td>
                    </tr>
                     <tr className="bg-white border-b">
                        <td className="px-6 py-4 font-medium text-slate-900">الكالسيوم (Ca)</td>
                        <td className="px-6 py-4">{needs.ca} g</td>
                        <td className="px-6 py-4">{supplied.ca} g</td>
                         <td className="px-6 py-4 ltr text-right">{supplied.ca - needs.ca}</td>
                        <td className="px-6 py-4">
                            <span className={`px-2 py-1 rounded text-xs font-bold ${getStatusColor(needs.ca, supplied.ca)}`}>
