import { CowParameters, Nutrients, RationItem, FeedIngredient } from '../types';
import { FEED_DATABASE } from '../constants';

export const calculateRequirements = (params: CowParameters): Nutrients => {
  let me = 0;
  let cp = 0;
  let ca = 0;
  let p = 0;

  const w075 = Math.pow(params.weight, 0.75);

  // 1. Maintenance (NASEM 2021 Adaptation)
  // Base NEm = 0.100 Mcal/kg BW^0.75 for modern dairy cows (increased from 0.08 in old NRC)
  // Converting NEm to ME approx: ME = NEm / 0.64 (roughly) => 0.100 / 0.64 ~= 0.156 ME_maint
  // However, simpler standard models often use ME directly.
  // Old NRC: ME_m = 0.13-0.14 * BW^0.75 (Total ME).
  // Let's use a robust base coefficient aligned with 2021 principles which assume higher metabolic rates.
  let meMaintCoeff = 0.14; // Base Mcal ME per kg BW^0.75

  // -- Environmental Adjustment (Naseem 2021 / NASEM 2021 principles) --
  // Heat stress increases maintenance energy due to panting and increased metabolic rate.
  // Cold stress increases maintenance due to shivering.
  if (params.environment === 'heat_mild') {
    meMaintCoeff *= 1.10; // +10%
  } else if (params.environment === 'heat_severe') {
    meMaintCoeff *= 1.25; // +25%
  } else if (params.environment === 'cold') {
    meMaintCoeff *= 1.15; // +15% (Variable, but simplified average)
  }

  // -- Grazing / Activity Adjustment --
  // NASEM 2021 calculates walking energy cost.
  // Flat grazing increases maintenance by ~10-15%.
  // Hilly grazing increases maintenance by ~20-30%+.
  let activityFactor = 1.0;
  if (params.grazing === 'flat') {
    activityFactor = 1.15;
  } else if (params.grazing === 'hilly') {
    activityFactor = 1.30;
  }

  // Calculate final Maintenance ME
  const meMaint = (meMaintCoeff * w075) * activityFactor;

  // Maintenance Protein
  // 4.0 g CP/kg BW^0.75 is standard, add small buffer for activity tissue turnover
  const cpMaint = (4.1 * w075) * activityFactor; 

  const caMaint = 0.0154 * params.weight;
  const pMaint = 0.0125 * params.weight;

  me += meMaint;
  cp += cpMaint;
  ca += caMaint;
  p += pMaint;

  // 2. Milk Production (NASEM 2021)
  // Energy: ME (Mcal/kg milk) = (0.0929 * Fat%) + 0.37 (Approx updated formula)
  // Or classic: 0.36 + 0.096*Fat. Let's use the slightly higher modern estimation.
  // 3.5% fat ~ 0.69 Mcal NEl ~ 1.1 Mcal ME.
  // Formula: ME_l (Mcal/kg) = (0.36 + 0.096 * Fat%) / 0.64 (efficiency of ME to Milk)
  // Standard efficiency ~0.64.
  const nelPerKgMilk = 0.36 + (0.096 * params.fatPercentage);
  const mePerKgMilk = nelPerKgMilk / 0.64; 
  me += params.milkProduction * mePerKgMilk;

  // CP: Modern cows often need more efficient RDP/RUP.
  // Crude Protein roughly 85-95g per kg milk depending on milk protein %.
  // Assuming standard 3.2% protein: (32g protein / 0.67 efficiency) ~ 48g MP ~ 80-90g CP.
  cp += params.milkProduction * 90; // Keeping 90g as safe standard

  ca += params.milkProduction * 1.22;
  p += params.milkProduction * 0.9;

  // 3. Pregnancy (Late gestation significantly increases needs)
  if (params.pregnancyMonth > 6) {
    // NASEM 2021 uses exponential growth curve for conceptus.
    // Simplified escalation:
    // Month 7: +2 Mcal ME
    // Month 8: +3.5 Mcal ME
    // Month 9: +5 Mcal ME
    const pregFactor = (params.pregnancyMonth - 6);
    me += 1.8 * pregFactor; // 1.8, 3.6, 5.4...
    cp += 110 * pregFactor;
    ca += 10 * pregFactor;
    p += 6 * pregFactor;
  }

  // 4. Growth (Primiparous / Heifers)
  // Needs 20% of maintenance extra + gain energy
  if (params.growthRate > 0) {
     // Cost of gain is high
     me += 5 * params.growthRate; // approx 5 Mcal ME per kg gain (tissue + skeletal)
     cp += 300 * params.growthRate;
     ca += 25 * params.growthRate;
     p += 15 * params.growthRate;
  }

  // 5. Body Condition Change (Mobilization or Repletion)
  // NASEM 2021:
  // 1 kg BCS gain (tissue) ~ 5.5 - 6.0 Mcal ME required (depending on efficiency).
  // 1 kg BCS loss (tissue) provides ~ 4.5 - 4.9 Mcal NEl ~ 7 Mcal ME sparing effect?
  // Let's stick to standard thermodynamic approximations.
  if (params.bcsChange > 0) {
      // Gaining weight
      me += 6.0 * params.bcsChange; 
      cp += 60 * params.bcsChange; // Tissue accretion needs some protein
  } else if (params.bcsChange < 0) {
      // Losing weight (mobilizing) - Reduces dietary need
      // Credit energy. Efficiency of mobilization is high.
      me += 4.9 * params.bcsChange; // Negative value reduces Requirement
      // Protein mobilization is usually not credited in formulation to ensure safety, 
      // but strictly speaking, it provides amino acids. We'll skip CP credit to be safe.
  }

  return {
    me: parseFloat(me.toFixed(2)),
    cp: Math.round(cp),
    ca: Math.round(ca),
    p: Math.round(p)
  };
};

export const calculateSupplied = (
  concentrateMix: RationItem[], 
  concentrateAmountFed: number, 
  forages: RationItem[]
): Nutrients & { totalDM: number, concentrateAnalysis: Nutrients } => {

  let totalME = 0;
  let totalCP = 0;
  let totalCa = 0;
  let totalP = 0;
  let totalDM = 0;

  // 1. Calculate Concentrate Mix Analysis (per 1kg of mix)
  const totalParts = concentrateMix.reduce((acc, item) => acc + item.amount, 0);

  let mixME = 0, mixCP = 0, mixCa = 0, mixP = 0;

  if (totalParts > 0) {
    concentrateMix.forEach(item => {
        const feed = FEED_DATABASE.find(f => f.id === item.ingredientId);
        if (feed) {
            const ratio = item.amount / totalParts; 
            const dmFactor = feed.dm / 100;

            mixME += (feed.me * dmFactor) * ratio;
            mixCP += (feed.cp * 10 * dmFactor) * ratio;
            mixCa += (feed.ca * 10 * dmFactor) * ratio;
            mixP += (feed.p * 10 * dmFactor) * ratio;
        }
    });
  }

  const concAnalysis = { me: mixME, cp: mixCP, ca: mixCa, p: mixP };

  // 2. Add Concentrate Supplied to Total
  totalME += mixME * concentrateAmountFed;
  totalCP += mixCP * concentrateAmountFed;
  totalCa += mixCa * concentrateAmountFed;
  totalP += mixP * concentrateAmountFed;

  const mixDM = concentrateMix.reduce((acc, item) => {
      const feed = FEED_DATABASE.find(f => f.id === item.ingredientId);
      return acc + (feed ? (feed.dm / 100) * (item.amount/totalParts) : 0);
  }, 0);
  totalDM += mixDM * concentrateAmountFed;

  // 3. Add Forages
  forages.forEach(item => {
      const feed = FEED_DATABASE.find(f => f.id === item.ingredientId);
      if (feed && item.amount > 0) {
          const dmFactor = feed.dm / 100;
          const kgDM = item.amount * dmFactor;

          totalME += feed.me * kgDM;
          totalCP += feed.cp * 10 * kgDM;
          totalCa += feed.ca * 10 * kgDM;
          totalP += feed.p * 10 * kgDM;
          totalDM += kgDM;
      }
  });

  return {
    me: parseFloat(totalME.toFixed(2)),
    cp: Math.round(totalCP),
    ca: Math.round(totalCa),
    p: Math.round(totalP),
    totalDM: parseFloat(totalDM.toFixed(2)),
    concentrateAnalysis: {
        me: parseFloat(mixME.toFixed(2)),
        cp: Math.round(mixCP),
        ca: Math.round(mixCa),
        p: Math.round(mixP)
    }
  };
};

