import React, { useMemo } from 'react';
import { RationItem, Nutrients } from '../types';
import { FEED_DATABASE } from '../constants';

interface FeedFormProps {
  concentrateMix: RationItem[];
  setConcentrateMix: (items: RationItem[]) => void;
  concentrateFedAmount: number;
  setConcentrateFedAmount: (n: number) => void;
  forages: RationItem[];
  setForages: (items: RationItem[]) => void;
  mixAnalysis: Nutrients;
}

const FeedForm: React.FC<FeedFormProps> = ({
  concentrateMix,
  setConcentrateMix,
  concentrateFedAmount,
  setConcentrateFedAmount,
  forages,
  setForages,
  mixAnalysis
}) => {

  const concentrateOptions = FEED_DATABASE.filter(f => f.type === 'concentrate');
  const forageOptions = FEED_DATABASE.filter(f => f.type === 'forage');

  const updateMixItem = (id: string, amount: number) => {
    const existing = concentrateMix.find(i => i.ingredientId === id);
    if (existing) {
      if (amount <= 0) {
        setConcentrateMix(concentrateMix.filter(i => i.ingredientId !== id));
      } else {
        setConcentrateMix(concentrateMix.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setConcentrateMix([...concentrateMix, { ingredientId: id, amount }]);
    }
  };

  const updateForageItem = (id: string, amount: number) => {
    const existing = forages.find(i => i.ingredientId === id);
    if (existing) {
       if (amount <= 0) {
        setForages(forages.filter(i => i.ingredientId !== id));
      } else {
        setForages(forages.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setForages([...forages, { ingredientId: id, amount }]);
    }
  };

  const totalMixPercentage = useMemo(() => 
    concentrateMix.reduce((acc, curr) => acc + curr.amount, 0), [concentrateMix]);

  return (
    <div className="space-y-8">

      {/* 1. Concentrate Mix Definition */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden border border-slate-200">
        <div className="bg-blue-50 px-6 py-4 border-b border-blue-100">
           <h2 className="text-xl font-bold text-blue-800">1. تركيب الخلطة المركزة (النسب المئوية)</h2>
           <p className="text-sm text-blue-600">حدد مكونات العلف المركز ونسبها (المجموع يفضل أن يكون 100% أو 1000 كغ)</p>
        </div>

        <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {concentrateOptions.map(feed => {
            const currentVal = concentrateMix.find(i => i.ingredientId === feed.id)?.amount || '';
            return (
              <div key={feed.id} className="flex items-center gap-2">
                 <label className="text-sm font-medium w-1/2 text-slate-700">{feed.name}</label>
                 <div className="relative w-1/2">
                    <input 
                      type="number"
                      min="0"
                      value={currentVal}
                      onChange={(e) => updateMixItem(feed.id, parseFloat(e.target.value) || 0)}
                      className="w-full p-2 pr-8 border rounded focus:ring-2 focus:ring-blue-500 outline-none text-left ltr"
                    />
                    <span className="absolute right-2 top-2 text-slate-400 text-xs">%</span>
                 </div>
              </div>
            );
          })}
        </div>
        <div className="bg-slate-50 px-6 py-3 border-t flex justify-between items-center">
            <span className="font-bold text-slate-700">المجموع الحالي للنسب:</span>
            <span className={`font-bold px-3 py-1 rounded ${Math.abs(totalMixPercentage - 100) < 0.1 ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                {totalMixPercentage}%
            </span>
        </div>
      </div>

      {/* Mix Analysis Result */}
