import { GoogleGenAI } from "@google/genai";
import { Nutrients, CowParameters } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const predictMetabolicHealth = async (
  cowParams: CowParameters,
  needs: Nutrients,
  supplied: Nutrients,
  forageToConcRatio: number
): Promise<string> => {
  const model = "gemini-3-flash-preview";

  const prompt = `
    أنت طبيب بيطري وخبير تغذية أبقار. قم بتحليل هذه العليقة وتوقع الأمراض الاستقلابية المحتملة.

    بيانات البقرة:
    الوزن: ${cowParams.weight} كغ
    انتاج الحليب: ${cowParams.milkProduction} كغ
    الحمل: شهر ${cowParams.pregnancyMonth}

    الاحتياجات مقابل المقدم:
    الطاقة: المقدم ${supplied.me} Mcal (${(supplied.me * 4.184).toFixed(1)} MJ) / المطلوب ${needs.me} Mcal (${(needs.me * 4.184).toFixed(1)} MJ)
    البروتين (g): المقدم ${supplied.cp} / المطلوب ${needs.cp}
    الكالسيوم (g): المقدم ${supplied.ca} / المطلوب ${needs.ca}
    الفوسفور (g): المقدم ${supplied.p} / المطلوب ${needs.p}

    نسبة العلف المالك للمركز تقريباً: ${forageToConcRatio.toFixed(2)}

    المطلوب:
    1. هل هناك خطر للإصابة بالحماض الكرشي (Acidosis)؟ لماذا؟
    2. هل هناك خطر للكيتوزيس (Ketosis)؟
    3. هل هناك خطر لحمى الحليب (Milk Fever)؟
    4. نصيحة قصيرة واحدة لتحسين العليقة.

    أجب باللغة العربية بأسلوب علمي ومختصر.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
    });
    return response.text || "لم يتمكن النظام من توليد تحليل حالياً.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "عذراً، حدث خطأ أثناء الاتصال بخدمة الذكاء الاصطناعي.";
  }
};

export interface CowParameters {
  weight: number; // kg
  milkProduction: number; // kg/day
  fatPercentage: number; // %
  pregnancyMonth: number; // 0-9
  growthRate: number; // kg/day (heifers)
  bcsChange: number; // -1 to +1 (loss/gain)
  lactationStage: 'early' | 'mid' | 'late';
  environment: 'neutral' | 'heat_mild' | 'heat_severe' | 'cold';
  grazing: 'none' | 'flat' | 'hilly';
}

export interface Nutrients {
  me: number; // Metabolizable Energy (Mcal)
  cp: number; // Crude Protein (g)
  ca: number; // Calcium (g)
  p: number; // Phosphorus (g)
}

export interface FeedIngredient {
  id: string;
  name: string;
  type: 'concentrate' | 'forage';
  dm: number; // Dry Matter %
  me: number; // Mcal/kg DM
  cp: number; // % DM
  ca: number; // % DM
  p: number; // % DM
  defaultPrice: number; // Price per kg
}

export interface RationItem {
  ingredientId: string;
  amount: number; // kg as fed
  isPercentage?: boolean; // For concentrate mix definition
}

export interface ConcentrateMix {
  ingredients: RationItem[];
  totalMixAmountFed: number; // kg fed to cow
}

export interface ForageRation {
  ingredients: RationItem[];
}

export enum Page {
  NEEDS = 'NEEDS',
  FEED = 'FEED',
  COMPARE = 'COMPARE',
  HEALTH = 'HEALTH'
}

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import NeedsForm from './components/NeedsForm';
import FeedForm from './components/FeedForm';
import Comparison from './components/Comparison';
import HealthAdvisor from './components/HealthAdvisor';
import { CowParameters, Nutrients, RationItem, Page } from './types';
import { calculateRequirements, calculateSupplied } from './services/calculator';
import { FEED_DATABASE } from './constants';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<Page>(Page.NEEDS);

  // State: Cow Parameters
  const [cowParams, setCowParams] = useState<CowParameters>({
    weight: 600,
    milkProduction: 25,
    fatPercentage: 3.8,
    pregnancyMonth: 5,
    growthRate: 0,
    bcsChange: 0,
    lactationStage: 'mid',
    environment: 'neutral',
    grazing: 'none'
  });

  // State: Requirements (Calculated)
  const [needs, setNeeds] = useState<Nutrients>({ me: 0, cp: 0, ca: 0, p: 0 });

  // State: Feed
  const [concentrateMix, setConcentrateMix] = useState<RationItem[]>([]);
  const [concentrateFedAmount, setConcentrateFedAmount] = useState<number>(0);
  const [forages, setForages] = useState<RationItem[]>([]);

  // State: Prices (map of ingredient ID to price)
  const [prices, setPrices] = useState<Record<string, number>>(() => {
    const initialPrices: Record<string, number> = {};
    FEED_DATABASE.forEach(feed => {
      initialPrices[feed.id] = feed.defaultPrice;
    });
    return initialPrices;
  });

  // State: Supplied (Calculated)
  const [supplied, setSupplied] = useState<Nutrients>({ me: 0, cp: 0, ca: 0, p: 0 });
  const [totalDM, setTotalDM] = useState<number>(0);
  const [mixAnalysis, setMixAnalysis] = useState<Nutrients>({ me: 0, cp: 0, ca: 0, p: 0 });

  // State: Cost
  const [totalCost, setTotalCost] = useState<number>(0);

  // Effects to trigger calculations
  useEffect(() => {
    const calculated = calculateRequirements(cowParams);
    setNeeds(calculated);
  }, [cowParams]);

  useEffect(() => {
    const result = calculateSupplied(concentrateMix, concentrateFedAmount, forages);
    setSupplied(result);
    setTotalDM(result.totalDM);
    setMixAnalysis(result.concentrateAnalysis);

    // Calculate Costs
    // 1. Concentrate Mix Cost per kg
    const totalMixWeight = concentrateMix.reduce((sum, item) => sum + item.amount, 0);
    let mixPricePerKg = 0;
    if (totalMixWeight > 0) {
        const totalMixCost = concentrateMix.reduce((sum, item) => sum + (item.amount * (prices[item.ingredientId] || 0)), 0);
        mixPricePerKg = totalMixCost / totalMixWeight;
    }

    // 2. Total Daily Cost
    let dailyCost = 0;
    // Cost of concentrate fed
    dailyCost += mixPricePerKg * concentrateFedAmount;
    // Cost of forages
    forages.forEach(f => {
        dailyCost += f.amount * (prices[f.ingredientId] || 0);
    });

    setTotalCost(dailyCost);

  }, [concentrateMix, concentrateFedAmount, forages, prices]);

  // Rough estimation of total forage amount for AI context
  const totalForageAmount = forages.reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <Layout activePage={activePage} setPage={setActivePage}>
      {activePage === Page.NEEDS && (
        <NeedsForm 
            params={cowParams} 
            setParams={setCowParams} 
            calculatedNeeds={needs} 
        />
      )}

      {activePage === Page.FEED && (
        <FeedForm 
            concentrateMix={concentrateMix}
            setConcentrateMix={setConcentrateMix}
            concentrateFedAmount={concentrateFedAmount}
            setConcentrateFedAmount={setConcentrateFedAmount}
            forages={forages}
            setForages={setForages}
            mixAnalysis={mixAnalysis}
            prices={prices}
            setPrices={setPrices}
        />
      )}

      {activePage === Page.COMPARE && (
        <Comparison 
            needs={needs}
            supplied={supplied}
            totalDM={totalDM}
            totalCost={totalCost}
            milkProduction={cowParams.milkProduction}
        />
      )}

      {activePage === Page.HEALTH && (
        <HealthAdvisor 
            params={cowParams}
            needs={needs}
            supplied={supplied}
            concentrateAmount={concentrateFedAmount}
            forageAmount={totalForageAmount}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useMemo } from 'react';
import { RationItem, Nutrients } from '../types';
import { FEED_DATABASE } from '../constants';
import { Coins, Calculator } from 'lucide-react';

interface FeedFormProps {
  concentrateMix: RationItem[];
  setConcentrateMix: (items: RationItem[]) => void;
  concentrateFedAmount: number;
  setConcentrateFedAmount: (n: number) => void;
  forages: RationItem[];
  setForages: (items: RationItem[]) => void;
  mixAnalysis: Nutrients;
  prices: Record<string, number>;
  setPrices: React.Dispatch<React.SetStateAction<Record<string, number>>>;
}

const FeedForm: React.FC<FeedFormProps> = ({
  concentrateMix,
  setConcentrateMix,
  concentrateFedAmount,
  setConcentrateFedAmount,
  forages,
  setForages,
  mixAnalysis,
  prices,
  setPrices
}) => {

  const concentrateOptions = FEED_DATABASE.filter(f => f.type === 'concentrate');
  const forageOptions = FEED_DATABASE.filter(f => f.type === 'forage');

  const updateMixItem = (id: string, amount: number) => {
    const existing = concentrateMix.find(i => i.ingredientId === id);
    if (existing) {
      if (amount <= 0) {
        setConcentrateMix(concentrateMix.filter(i => i.ingredientId !== id));
      } else {
        setConcentrateMix(concentrateMix.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setConcentrateMix([...concentrateMix, { ingredientId: id, amount }]);
    }
  };

  const updateForageItem = (id: string, amount: number) => {
    const existing = forages.find(i => i.ingredientId === id);
    if (existing) {
       if (amount <= 0) {
        setForages(forages.filter(i => i.ingredientId !== id));
      } else {
        setForages(forages.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setForages([...forages, { ingredientId: id, amount }]);
    }
  };

  const updatePrice = (id: string, price: number) => {
      setPrices(prev => ({...prev, [id]: price}));
  };

  const totalMixPercentage = useMemo(() => 
    concentrateMix.reduce((acc, curr) => acc + curr.amount, 0), [concentrateMix]);

  // Calculate Mix Price
  const mixPricePerKg = useMemo(() => {
    if (totalMixPercentage === 0) return 0;
    const totalCost = concentrateMix.reduce((acc, item) => acc + (item.amount * (prices[item.ingredientId] || 0)), 0);
    return totalCost / totalMixPercentage;
  }, [concentrateMix, prices, totalMixPercentage]);

  return (
    <div className="space-y-8">

      {/* 1. Concentrate Mix Definition */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden border border-slate-200">
        <div className="bg-blue-50 px-6 py-4 border-b border-blue-100 flex justify-between items-center">
           <div>
            <h2 className="text-xl font-bold text-blue-800">1. تركيب الخلطة المركزة</h2>
            <p className="text-sm text-blue-600">حدد النسب المئوية وسعر المكونات</p>
           </div>
           <div className="bg-white px-3 py-1 rounded text-blue-800 text-sm font-bold shadow-sm">
             سعر 1 كغ خلطة: {mixPricePerKg.toFixed(2)}
           </div>
        </div>

        <div className="p-6">
          <div className="grid grid-cols-12 gap-4 text-xs font-bold text-slate-500 mb-2 px-2">
            <div className="col-span-4">المادة العلفية</div>
            <div className="col-span-4">النسبة %</div>
            <div className="col-span-4">السعر/كغ</div>
          </div>
          <div className="space-y-3">
          {concentrateOptions.map(feed => {
            const currentVal = concentrateMix.find(i => i.ingredientId === feed.id)?.amount || '';
            const currentPrice = prices[feed.id] || 0;
            return (
              <div key={feed.id} className="grid grid-cols-12 gap-4 items-center">
                 <label className="col-span-4 text-sm font-medium text-slate-700">{feed.name}</label>

                 <div className="col-span-4 relative">
                    <input 
                      type="number"
                      min="0"
                      value={currentVal}
                      onChange={(e) => updateMixItem(feed.id, parseFloat(e.target.value) || 0)}
                      className="w-full p-2 pr-6 border rounded focus:ring-2 focus:ring-blue-500 outline-none ltr text-left bg-slate-50"
                      placeholder="0"
                    />
                    <span className="absolute right-2 top-2 text-slate-400 text-xs">%</span>
                 </div>

                 <div className="col-span-4 relative">
                    <input 
                      type="number"
                      min="0"
                      step="0.1"
                      value={currentPrice}
                      onChange={(e) => updatePrice(feed.id, parseFloat(e.target.value) || 0)}
                      className="w-full p-2 pr-8 border rounded focus:ring-2 focus:ring-yellow-500 outline-none ltr text-left"
                    />
                    <Coins className="w-3 h-3 text-yellow-500 absolute right-2 top-3" />
                 </div>
              </div>
            );
          })}
          </div>
        </div>
        <div className="bg-slate-50 px-6 py-3 border-t flex justify-between items-center">
            <span className="font-bold text-slate-700">المجموع الحالي للنسب:</span>
            <span className={`font-bold px-3 py-1 rounded ${Math.abs(totalMixPercentage - 100) < 0.1 ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                {totalMixPercentage}%
            </span>
        </div>
      </div>

      {/* Mix Analysis Result */}
      <div className="bg-blue-600 text-white rounded-xl p-6 shadow-lg relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-400 to-blue-800"></div>
          <h3 className="font-bold mb-4 flex items-center gap-2">
            <Calculator className="w-5 h-5" />
            محتوى الخلطة المركزة (لكل 1 كغ علف):
          </h3>
