import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import NeedsForm from './components/NeedsForm';
import FeedForm from './components/FeedForm';
import Comparison from './components/Comparison';
import HealthAdvisor from './components/HealthAdvisor';
import { CowParameters, Nutrients, RationItem, Page, FeedIngredient } from './types';
import { calculateRequirements, calculateSupplied } from './services/calculator';
import { FEED_DATABASE } from './constants';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<Page>(Page.NEEDS);

  // State: Cow Parameters
  const initialCowParams: CowParameters = {
    weight: 600,
    milkProduction: 25,
    fatPercentage: 3.8,
    pregnancyMonth: 5,
    growthRate: 0,
    bcsChange: 0,
    lactationStage: 'mid',
    environment: 'neutral',
    grazing: 'none'
  };
  const [cowParams, setCowParams] = useState<CowParameters>(initialCowParams);

  // State: Requirements (Calculated)
  const [needs, setNeeds] = useState<Nutrients>({ me: 0, cp: 0, ca: 0, p: 0 });

  // State: Ingredients (Initialized from constant, but mutable)
  const [ingredients, setIngredients] = useState<FeedIngredient[]>(FEED_DATABASE);

  // State: Feed
  const [concentrateMix, setConcentrateMix] = useState<RationItem[]>([]);
  const [concentrateFedAmount, setConcentrateFedAmount] = useState<number>(0);
  const [forages, setForages] = useState<RationItem[]>([]);

  // State: Supplied (Calculated)
  const [supplied, setSupplied] = useState<Nutrients>({ me: 0, cp: 0, ca: 0, p: 0 });
  const [totalDM, setTotalDM] = useState<number>(0);
  const [mixAnalysis, setMixAnalysis] = useState<Nutrients>({ me: 0, cp: 0, ca: 0, p: 0 });

  // State: Cost
  const [totalCost, setTotalCost] = useState<number>(0);

  const handleReset = () => {
    if (window.confirm("هل أنت متأكد من رغبتك في بدء جلسة جديدة؟ سيتم مسح جميع المدخلات.")) {
        setCowParams(initialCowParams);
        setConcentrateMix([]);
        setConcentrateFedAmount(0);
        setForages([]);
        setIngredients(FEED_DATABASE); // Optional: Reset ingredients to default or keep them? Usually resetting keeps custom DB for session, but prompt implied "Close/New". Let's reset inputs but maybe keep ingredients? No, let's full reset for "New Session".
        setActivePage(Page.NEEDS);
        window.scrollTo(0, 0);
    }
  };

  // Effects to trigger calculations
  useEffect(() => {
    const calculated = calculateRequirements(cowParams);
    setNeeds(calculated);
  }, [cowParams]);

  useEffect(() => {
    const result = calculateSupplied(concentrateMix, concentrateFedAmount, forages, ingredients);
    setSupplied(result);
    setTotalDM(result.totalDM);
    setMixAnalysis(result.concentrateAnalysis);

    // Calculate Costs
    // 1. Concentrate Mix Cost per kg
    const totalMixWeight = concentrateMix.reduce((sum, item) => sum + item.amount, 0);
    let mixPricePerKg = 0;
    if (totalMixWeight > 0) {
        const totalMixCost = concentrateMix.reduce((sum, item) => {
            const ing = ingredients.find(i => i.id === item.ingredientId);
            return sum + (item.amount * (ing?.defaultPrice || 0));
        }, 0);
        mixPricePerKg = totalMixCost / totalMixWeight;
    }

    // 2. Total Daily Cost
    let dailyCost = 0;
    // Cost of concentrate fed
    dailyCost += mixPricePerKg * concentrateFedAmount;
    // Cost of forages
    forages.forEach(f => {
        const ing = ingredients.find(i => i.id === f.ingredientId);
        dailyCost += f.amount * (ing?.defaultPrice || 0);
    });

    setTotalCost(dailyCost);

  }, [concentrateMix, concentrateFedAmount, forages, ingredients]);

  // Rough estimation of total forage amount for AI context
  const totalForageAmount = forages.reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <Layout activePage={activePage} setPage={setActivePage} onReset={handleReset}>
      {activePage === Page.NEEDS && (
        <NeedsForm 
            params={cowParams} 
            setParams={setCowParams} 
            calculatedNeeds={needs} 
        />
      )}

      {activePage === Page.FEED && (
        <FeedForm 
            concentrateMix={concentrateMix}
            setConcentrateMix={setConcentrateMix}
            concentrateFedAmount={concentrateFedAmount}
            setConcentrateFedAmount={setConcentrateFedAmount}
            forages={forages}
            setForages={setForages}
            mixAnalysis={mixAnalysis}
            ingredients={ingredients}
            setIngredients={setIngredients}
            prices={{}} // Deprecated prop
            setPrices={() => {}} // Deprecated prop
        />
      )}

      {activePage === Page.COMPARE && (
        <Comparison 
            needs={needs}
            supplied={supplied}
            totalDM={totalDM}
            totalCost={totalCost}
            milkProduction={cowParams.milkProduction}
        />
      )}

      {activePage === Page.HEALTH && (
        <HealthAdvisor 
            params={cowParams}
            needs={needs}
            supplied={supplied}
            concentrateAmount={concentrateFedAmount}
            forageAmount={totalForageAmount}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { RationItem, Nutrients, FeedIngredient } from '../types';
import { Calculator, Settings, Plus, X, Save } from 'lucide-react';

interface FeedFormProps {
  concentrateMix: RationItem[];
  setConcentrateMix: (items: RationItem[]) => void;
  concentrateFedAmount: number;
  setConcentrateFedAmount: (n: number) => void;
  forages: RationItem[];
  setForages: (items: RationItem[]) => void;
  mixAnalysis: Nutrients;
  ingredients: FeedIngredient[];
  setIngredients: (items: FeedIngredient[]) => void;
}

const FeedForm: React.FC<FeedFormProps> = ({
  concentrateMix,
  setConcentrateMix,
  concentrateFedAmount,
  setConcentrateFedAmount,
  forages,
  setForages,
  mixAnalysis,
  ingredients,
  setIngredients
}) => {

  const [editingIngredient, setEditingIngredient] = useState<FeedIngredient | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const concentrateOptions = ingredients.filter(f => f.type === 'concentrate');
  const forageOptions = ingredients.filter(f => f.type === 'forage');

  const updateMixItem = (id: string, amount: number) => {
    const existing = concentrateMix.find(i => i.ingredientId === id);
    if (existing) {
      if (amount <= 0) {
        setConcentrateMix(concentrateMix.filter(i => i.ingredientId !== id));
      } else {
        setConcentrateMix(concentrateMix.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setConcentrateMix([...concentrateMix, { ingredientId: id, amount }]);
    }
  };

  const updateForageItem = (id: string, amount: number) => {
    const existing = forages.find(i => i.ingredientId === id);
    if (existing) {
       if (amount <= 0) {
        setForages(forages.filter(i => i.ingredientId !== id));
      } else {
        setForages(forages.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setForages([...forages, { ingredientId: id, amount }]);
    }
  };

  const totalMixPercentage = useMemo(() => 
    concentrateMix.reduce((acc, curr) => acc + curr.amount, 0), [concentrateMix]);

  // Calculate Mix Price
  const mixPricePerKg = useMemo(() => {
    if (totalMixPercentage === 0) return 0;
    const totalCost = concentrateMix.reduce((acc, item) => {
        const ing = ingredients.find(i => i.id === item.ingredientId);
        return acc + (item.amount * (ing?.defaultPrice || 0));
    }, 0);
    return totalCost / totalMixPercentage;
  }, [concentrateMix, ingredients, totalMixPercentage]);

  // -- Ingredient Management --

  const openEditModal = (ingredient: FeedIngredient) => {
    setEditingIngredient({ ...ingredient });
    setIsModalOpen(true);
  };

  const openNewModal = (type: 'concentrate' | 'forage') => {
    setEditingIngredient({
        id: `custom_${Date.now()}`,
        name: 'مادة جديدة',
        type: type,
        dm: 90,
        me: 2.0,
        cp: 10,
        ca: 0.1,
        p: 0.1,
        defaultPrice: 0
    });
    setIsModalOpen(true);
  };

  const saveIngredient = () => {
      if (!editingIngredient) return;

      const exists = ingredients.find(i => i.id === editingIngredient.id);
      if (exists) {
          setIngredients(ingredients.map(i => i.id === editingIngredient.id ? editingIngredient : i));
      } else {
          setIngredients([...ingredients, editingIngredient]);
      }
      setIsModalOpen(false);
      setEditingIngredient(null);
  };

  const handleModalChange = (field: keyof FeedIngredient, value: string | number) => {
      if (!editingIngredient) return;
      setEditingIngredient({
          ...editingIngredient,
          [field]: typeof value === 'number' ? value : value
      });
  };

  return (
    <div className="space-y-8">

      {/* 1. Concentrate Mix Definition */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden border border-slate-200">
        <div className="bg-blue-50 px-6 py-4 border-b border-blue-100 flex justify-between items-center">
           <div>
            <h2 className="text-xl font-bold text-blue-800">1. تركيب الخلطة المركزة</h2>
            <p className="text-sm text-blue-600">حدد النسب المئوية للمكونات</p>
           </div>
           <div className="bg-white px-3 py-1 rounded text-blue-800 text-sm font-bold shadow-sm">
             سعر 1 كغ خلطة: {mixPricePerKg.toFixed(2)}
           </div>
        </div>

        <div className="p-6">
          <div className="grid grid-cols-12 gap-4 text-xs font-bold text-slate-500 mb-2 px-2">
            <div className="col-span-4">المادة العلفية</div>
            <div className="col-span-4">النسبة %</div>
            <div className="col-span-4">تعديل</div>
          </div>
          <div className="space-y-3">
          {concentrateOptions.map(feed => {
            const currentVal = concentrateMix.find(i => i.ingredientId === feed.id)?.amount || '';
            return (
              <div key={feed.id} className="grid grid-cols-12 gap-4 items-center">
                 <label className="col-span-4 text-sm font-medium text-slate-700 flex flex-col">
                    <span>{feed.name}</span>
                    <span className="text-xs text-slate-400 font-normal">{feed.defaultPrice} عملة/كغ</span>
                 </label>

                 <div className="col-span-4 relative">
                    <input 
                      type="number"
                      min="0"
                      value={currentVal}
                      onChange={(e) => updateMixItem(feed.id, parseFloat(e.target.value) || 0)}
                      className="w-full p-2 pr-6 border rounded focus:ring-2 focus:ring-blue-500 outline-none ltr text-left bg-slate-50"
                      placeholder="0"
                    />
                    <span className="absolute right-2 top-2 text-slate-400 text-xs">%</span>
                 </div>

                 <div className="col-span-4">
                    <button 
                        onClick={() => openEditModal(feed)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded transition-colors"
                        title="تعديل خصائص المادة"
                    >
                        <Settings className="w-4 h-4" />
                    </button>
                 </div>
              </div>
            );
          })}
          </div>
          <button 
            onClick={() => openNewModal('concentrate')}
            className="mt-6 w-full py-2 border-2 border-dashed border-blue-200 text-blue-600 rounded-lg hover:bg-blue-50 hover:border-blue-400 transition-all flex items-center justify-center gap-2 font-medium"
          >
            <Plus className="w-4 h-4" /> إضافة مادة مركزة جديدة
          </button>
        </div>
        <div className="bg-slate-50 px-6 py-3 border-t flex justify-between items-center">
            <span className="font-bold text-slate-700">المجموع الحالي للنسب:</span>
            <span className={`font-bold px-3 py-1 rounded ${Math.abs(totalMixPercentage - 100) < 0.1 ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                {totalMixPercentage}%
            </span>
        </div>
      </div>

      {/* Mix Analysis Result */}
      <div className="bg-blue-600 text-white rounded-xl p-6 shadow-lg relative overflow-hidden print-break-inside-avoid">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-400 to-blue-800"></div>
          <h3 className="font-bold mb-4 flex items-center gap-2">
            <Calculator className="w-5 h-5" />
            محتوى الخلطة المركزة (لكل 1 كغ علف):
          </h3>
          <div className="grid grid-cols-4 gap-4 text-center">
              <div>
                  <div className="text-2xl font-bold">{mixAnalysis.me}</div>
                  <div className="text-xs opacity-80">Mcal/kg</div>
                  <div className="text-sm font-bold opacity-90 mt-1 ltr">
                    {(mixAnalysis.me * 4.184).toFixed(1)} <span className="text-[10px]">MJ/kg</span>
                  </div>
              </div>
              <div>
                  <div className="text-2xl font-bold">{(mixAnalysis.cp / 10).toFixed(1)}%</div>
                  <div className="text-xs opacity-80">بروتين خام</div>
              </div>
              <div>
                  <div className="text-2xl font-bold">{(mixAnalysis.ca / 10).toFixed(2)}%</div>
                  <div className="text-xs opacity-80">كالسيوم</div>
              </div>
               <div>
                  <div className="text-2xl font-bold">{(mixAnalysis.p / 10).toFixed(2)}%</div>
                  <div className="text-xs opacity-80">فوسفور</div>
              </div>
