import { CowParameters, Nutrients, RationItem, FeedIngredient } from '../types';

export const calculateRequirements = (params: CowParameters): Nutrients => {
  let me = 0;
  let cp = 0;
  let ca = 0;
  let p = 0;

  const w075 = Math.pow(params.weight, 0.75);

  // 1. Maintenance (NASEM 2021 Adaptation)
  let meMaintCoeff = 0.14; 

  if (params.environment === 'heat_mild') {
    meMaintCoeff *= 1.10; 
  } else if (params.environment === 'heat_severe') {
    meMaintCoeff *= 1.25; 
  } else if (params.environment === 'cold') {
    meMaintCoeff *= 1.15; 
  }

  let activityFactor = 1.0;
  if (params.grazing === 'flat') {
    activityFactor = 1.15;
  } else if (params.grazing === 'hilly') {
    activityFactor = 1.30;
  }

  const meMaint = (meMaintCoeff * w075) * activityFactor;
  const cpMaint = (4.1 * w075) * activityFactor; 

  const caMaint = 0.0154 * params.weight;
  const pMaint = 0.0125 * params.weight;

  me += meMaint;
  cp += cpMaint;
  ca += caMaint;
  p += pMaint;

  // 2. Milk Production
  const nelPerKgMilk = 0.36 + (0.096 * params.fatPercentage);
  const mePerKgMilk = nelPerKgMilk / 0.64; 
  me += params.milkProduction * mePerKgMilk;

  cp += params.milkProduction * 90; 
  ca += params.milkProduction * 1.22;
  p += params.milkProduction * 0.9;

  // 3. Pregnancy
  if (params.pregnancyMonth > 6) {
    const pregFactor = (params.pregnancyMonth - 6);
    me += 1.8 * pregFactor; 
    cp += 110 * pregFactor;
    ca += 10 * pregFactor;
    p += 6 * pregFactor;
  }

  // 4. Growth
  if (params.growthRate > 0) {
     me += 5 * params.growthRate; 
     cp += 300 * params.growthRate;
     ca += 25 * params.growthRate;
     p += 15 * params.growthRate;
  }

  // 5. Body Condition Change
  if (params.bcsChange > 0) {
      me += 6.0 * params.bcsChange; 
      cp += 60 * params.bcsChange; 
  } else if (params.bcsChange < 0) {
      me += 4.9 * params.bcsChange; 
  }

  // --- New Calculations for Fiber & Starch ---
  // Estimate Dry Matter Intake (DMI) for calculating fiber requirements
  // Simple approximation: DMI (kg) = 0.025 * BW + 0.1 * Milk
  const estimatedDMI = (0.025 * params.weight) + (0.1 * params.milkProduction);

  // Guidelines (approximate):
  // Min NDF: 30% of DM
  // Min ADF: 21% of DM
  // Max Starch: 25% of DM (Safety limit)
  // Sugar: ~5% (Guideline)

  const ndfReq = estimatedDMI * 1000 * 0.30; // in grams
  const adfReq = estimatedDMI * 1000 * 0.21; // in grams
  const starchMax = estimatedDMI * 1000 * 0.25; // in grams (Max limit)
  const sugarReq = estimatedDMI * 1000 * 0.05; // in grams (Rough target)

  return {
    me: parseFloat(me.toFixed(2)),
    cp: Math.round(cp),
    ca: Math.round(ca),
    p: Math.round(p),
    ndf: Math.round(ndfReq),
    adf: Math.round(adfReq),
    starch: Math.round(starchMax), // Note: This is a MAX limit, not min requirement
    sugar: Math.round(sugarReq)
  };
};

export const calculateSupplied = (
  concentrateMix: RationItem[], 
  concentrateAmountFed: number, 
  forages: RationItem[],
  feedDatabase: FeedIngredient[] 
): Nutrients & { totalDM: number, concentrateAnalysis: Nutrients } => {

  let totalME = 0;
  let totalCP = 0;
  let totalCa = 0;
  let totalP = 0;
  let totalStarch = 0;
  let totalSugar = 0;
  let totalNDF = 0;
  let totalADF = 0;
  let totalDM = 0;

  // 1. Calculate Concentrate Mix Analysis (per 1kg of mix)
  const totalParts = concentrateMix.reduce((acc, item) => acc + item.amount, 0);

  let mixME = 0, mixCP = 0, mixCa = 0, mixP = 0, mixStarch = 0, mixSugar = 0, mixNDF = 0, mixADF = 0;

  if (totalParts > 0) {
    concentrateMix.forEach(item => {
        const feed = feedDatabase.find(f => f.id === item.ingredientId);
        if (feed) {
            const ratio = item.amount / totalParts; 
            const dmFactor = feed.dm / 100;

            mixME += (feed.me * dmFactor) * ratio;
            mixCP += (feed.cp * 10 * dmFactor) * ratio;
            mixCa += (feed.ca * 10 * dmFactor) * ratio;
            mixP += (feed.p * 10 * dmFactor) * ratio;
            mixStarch += (feed.starch * 10 * dmFactor) * ratio;
            mixSugar += (feed.sugar * 10 * dmFactor) * ratio;
            mixNDF += (feed.ndf * 10 * dmFactor) * ratio;
            mixADF += (feed.adf * 10 * dmFactor) * ratio;
        }
    });
  }

  const concAnalysis = { me: mixME, cp: mixCP, ca: mixCa, p: mixP, starch: mixStarch, sugar: mixSugar, ndf: mixNDF, adf: mixADF };

  // 2. Add Concentrate Supplied to Total
  totalME += mixME * concentrateAmountFed;
  totalCP += mixCP * concentrateAmountFed;
  totalCa += mixCa * concentrateAmountFed;
  totalP += mixP * concentrateAmountFed;
  totalStarch += mixStarch * concentrateAmountFed;
  totalSugar += mixSugar * concentrateAmountFed;
  totalNDF += mixNDF * concentrateAmountFed;
  totalADF += mixADF * concentrateAmountFed;

  const mixDM = concentrateMix.reduce((acc, item) => {
      const feed = feedDatabase.find(f => f.id === item.ingredientId);
      return acc + (feed ? (feed.dm / 100) * (item.amount/totalParts) : 0);
  }, 0);
  totalDM += mixDM * concentrateAmountFed;

  // 3. Add Forages
  forages.forEach(item => {
      const feed = feedDatabase.find(f => f.id === item.ingredientId);
      if (feed && item.amount > 0) {
          const dmFactor = feed.dm / 100;
          const kgDM = item.amount * dmFactor;

          totalME += feed.me * kgDM;
          totalCP += feed.cp * 10 * kgDM;
          totalCa += feed.ca * 10 * kgDM;
          totalP += feed.p * 10 * kgDM;

          // Add new nutrients
          totalStarch += feed.starch * 10 * kgDM;
          totalSugar += feed.sugar * 10 * kgDM;
          totalNDF += feed.ndf * 10 * kgDM;
          totalADF += feed.adf * 10 * kgDM;

          totalDM += kgDM;
      }
  });

  return {
    me: parseFloat(totalME.toFixed(2)),
    cp: Math.round(totalCP),
    ca: Math.round(totalCa),
    p: Math.round(totalP),
    starch: Math.round(totalStarch),
    sugar: Math.round(totalSugar),
    ndf: Math.round(totalNDF),
    adf: Math.round(totalADF),
    totalDM: parseFloat(totalDM.toFixed(2)),
    concentrateAnalysis: {
        me: parseFloat(mixME.toFixed(2)),
        cp: Math.round(mixCP),
        ca: Math.round(mixCa),
        p: Math.round(mixP),
        starch: Math.round(mixStarch),
        sugar: Math.round(mixSugar),
        ndf: Math.round(mixNDF),
        adf: Math.round(mixADF)
    }
  };
};

import React, { useMemo, useState } from 'react';
import { RationItem, Nutrients, FeedIngredient } from '../types';
import { Calculator, Settings, Plus, X, Save } from 'lucide-react';

interface FeedFormProps {
  concentrateMix: RationItem[];
  setConcentrateMix: (items: RationItem[]) => void;
  concentrateFedAmount: number;
  setConcentrateFedAmount: (n: number) => void;
  forages: RationItem[];
  setForages: (items: RationItem[]) => void;
  mixAnalysis: Nutrients;
  ingredients: FeedIngredient[];
  setIngredients: (items: FeedIngredient[]) => void;
}

const FeedForm: React.FC<FeedFormProps> = ({
  concentrateMix,
  setConcentrateMix,
  concentrateFedAmount,
  setConcentrateFedAmount,
  forages,
  setForages,
  mixAnalysis,
  ingredients,
  setIngredients
}) => {

  const [editingIngredient, setEditingIngredient] = useState<FeedIngredient | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const concentrateOptions = ingredients.filter(f => f.type === 'concentrate');
  const forageOptions = ingredients.filter(f => f.type === 'forage');

  const updateMixItem = (id: string, amount: number) => {
    const existing = concentrateMix.find(i => i.ingredientId === id);
    if (existing) {
      if (amount <= 0) {
        setConcentrateMix(concentrateMix.filter(i => i.ingredientId !== id));
      } else {
        setConcentrateMix(concentrateMix.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setConcentrateMix([...concentrateMix, { ingredientId: id, amount }]);
    }
  };

  const updateForageItem = (id: string, amount: number) => {
    const existing = forages.find(i => i.ingredientId === id);
    if (existing) {
       if (amount <= 0) {
        setForages(forages.filter(i => i.ingredientId !== id));
      } else {
        setForages(forages.map(i => i.ingredientId === id ? { ...i, amount } : i));
      }
    } else if (amount > 0) {
      setForages([...forages, { ingredientId: id, amount }]);
    }
  };

  const totalMixPercentage = useMemo(() => 
    concentrateMix.reduce((acc, curr) => acc + curr.amount, 0), [concentrateMix]);

  // Calculate Mix Price
  const mixPricePerKg = useMemo(() => {
    if (totalMixPercentage === 0) return 0;
    const totalCost = concentrateMix.reduce((acc, item) => {
        const ing = ingredients.find(i => i.id === item.ingredientId);
        return acc + (item.amount * (ing?.defaultPrice || 0));
    }, 0);
    return totalCost / totalMixPercentage;
  }, [concentrateMix, ingredients, totalMixPercentage]);

  // -- Ingredient Management --

  const openEditModal = (ingredient: FeedIngredient) => {
    setEditingIngredient({ ...ingredient });
    setIsModalOpen(true);
  };

  const openNewModal = (type: 'concentrate' | 'forage') => {
    setEditingIngredient({
        id: `custom_${Date.now()}`,
        name: 'مادة جديدة',
        type: type,
        dm: 90,
        me: 2.0,
        cp: 10,
        ca: 0.1,
        p: 0.1,
        starch: 0,
        sugar: 0,
        ndf: 10,
        adf: 5,
        defaultPrice: 0
    });
    setIsModalOpen(true);
  };

  const saveIngredient = () => {
      if (!editingIngredient) return;

      const exists = ingredients.find(i => i.id === editingIngredient.id);
      if (exists) {
          setIngredients(ingredients.map(i => i.id === editingIngredient.id ? editingIngredient : i));
      } else {
          setIngredients([...ingredients, editingIngredient]);
      }
      setIsModalOpen(false);
      setEditingIngredient(null);
  };

  const handleModalChange = (field: keyof FeedIngredient, value: string | number) => {
      if (!editingIngredient) return;
      setEditingIngredient({
          ...editingIngredient,
          [field]: typeof value === 'number' ? value : value
      });
  };

  return (
    <div className="space-y-8">

      {/* 1. Concentrate Mix Definition */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden border border-slate-200">
        <div className="bg-blue-50 px-6 py-4 border-b border-blue-100 flex justify-between items-center">
           <div>
            <h2 className="text-xl font-bold text-blue-800">1. تركيب الخلطة المركزة</h2>
            <p className="text-sm text-blue-600">حدد النسب المئوية للمكونات</p>
           </div>
           <div className="bg-white px-3 py-1 rounded text-blue-800 text-sm font-bold shadow-sm">
             سعر 1 كغ خلطة: {mixPricePerKg.toFixed(2)}
           </div>
        </div>

        <div className="p-6">
          <div className="grid grid-cols-12 gap-4 text-xs font-bold text-slate-500 mb-2 px-2">
            <div className="col-span-4">المادة العلفية</div>
            <div className="col-span-4">النسبة %</div>
            <div className="col-span-4">تعديل</div>
          </div>
          <div className="space-y-3">
          {concentrateOptions.map(feed => {
            const currentVal = concentrateMix.find(i => i.ingredientId === feed.id)?.amount || '';
            return (
              <div key={feed.id} className="grid grid-cols-12 gap-4 items-center">
                 <label className="col-span-4 text-sm font-medium text-slate-700 flex flex-col">
                    <span>{feed.name}</span>
                    <span className="text-xs text-slate-400 font-normal">{feed.defaultPrice} عملة/كغ</span>
                 </label>

                 <div className="col-span-4 relative">
                    <input 
                      type="number"
                      min="0"
                      value={currentVal}
                      onChange={(e) => updateMixItem(feed.id, parseFloat(e.target.value) || 0)}
                      className="w-full p-2 pr-6 border rounded focus:ring-2 focus:ring-blue-500 outline-none ltr text-left bg-slate-50"
                      placeholder="0"
                    />
                    <span className="absolute right-2 top-2 text-slate-400 text-xs">%</span>
                 </div>

                 <div className="col-span-4">
                    <button 
