import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Nutrients } from '../types';
import { Coins, TrendingUp, Printer, XCircle } from 'lucide-react';

interface ComparisonProps {
  needs: Nutrients;
  supplied: Nutrients;
  totalDM: number;
  totalCost: number;
  milkProduction: number;
}

const Comparison: React.FC<ComparisonProps> = ({ needs, supplied, totalDM, totalCost, milkProduction }) => {

  const data = [
    { name: 'الطاقة (Mcal)', required: needs.me, supplied: supplied.me, unit: 'Mcal' },
    { name: 'البروتين (g/10)', required: Math.round(needs.cp / 10), supplied: Math.round(supplied.cp / 10), unit: 'x10 g' },
    { name: 'Ca (g)', required: needs.ca, supplied: supplied.ca, unit: 'g' },
    { name: 'NDF (g/10)', required: Math.round(needs.ndf/10), supplied: Math.round(supplied.ndf/10), unit: 'x10 g' },
  ];

  const getStatusColor = (req: number, sup: number, isMaxLimit: boolean = false) => {
    // If it's a Max Limit (like Starch), exceeding it is bad (Red), being under is generally OK (Green/Yellow)
    if (isMaxLimit) {
        if (sup > req) return 'text-red-600 bg-red-50'; // Exceeded max
        return 'text-green-600 bg-green-50'; // Safe
    }

    const diff = ((sup - req) / req) * 100;
    if (diff < -10) return 'text-red-600 bg-red-50';
    if (diff > 20) return 'text-yellow-600 bg-yellow-50'; // Warning overfeeding
    return 'text-green-600 bg-green-50';
  };

  const getStatusText = (req: number, sup: number, isMaxLimit: boolean = false) => {
      if (isMaxLimit) {
          if (sup > req) return `تجاوز الحد (${Math.round(((sup - req)/req)*100)}%)`;
          return 'آمن';
      }

      const diff = ((sup - req) / req) * 100;
      if (diff < -10) return `نقص (${Math.abs(Math.round(diff))}%)`;
      if (diff > 20) return `زائد (${Math.round(diff)}%)`;
      return 'متوازن';
  };

  const costPerKgMilk = milkProduction > 0 ? totalCost / milkProduction : 0;

  const handlePrint = () => {
    window.print();
  };

  const handleClose = () => {
    if(confirm('هل تريد إعادة تعيين التطبيق والبدء من جديد؟')) {
        window.location.reload();
    }
  };

  return (
    <div className="space-y-8">
        {/* Economic Analysis */}
        <div className="bg-gradient-to-r from-slate-800 to-slate-900 text-white p-6 rounded-xl shadow-lg print-break-inside-avoid">
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                <Coins className="text-yellow-400" />
                التحليل الاقتصادي (يومياً)
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 text-center">
                <div className="bg-white/10 p-4 rounded-lg backdrop-blur-sm">
                    <p className="text-slate-300 text-sm mb-1">تكلفة العليقة اليومية</p>
                    <p className="text-3xl font-bold text-yellow-400">{totalCost.toFixed(2)} <span className="text-sm">عملة</span></p>
                </div>
                <div className="bg-white/10 p-4 rounded-lg backdrop-blur-sm">
                    <p className="text-slate-300 text-sm mb-1">تكلفة إنتاج 1 كغ حليب</p>
                    <p className="text-3xl font-bold text-green-400">{costPerKgMilk.toFixed(2)} <span className="text-sm">عملة/كغ</span></p>
                </div>
                 <div className="bg-white/10 p-4 rounded-lg backdrop-blur-sm">
                    <p className="text-slate-300 text-sm mb-1">كفاءة التحويل (حليب/علف جاف)</p>
                    <p className="text-3xl font-bold text-blue-400">{(totalDM > 0 ? milkProduction / totalDM : 0).toFixed(2)}</p>
                </div>
            </div>
        </div>

      <div className="bg-white p-6 rounded-xl shadow-md border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
            <TrendingUp className="text-emerald-600" />
