export interface CowParameters {
  weight: number; // kg
  milkProduction: number; // kg/day
  fatPercentage: number; // %
  proteinPercentage: number; // % (New: Required for NASEM 2021 ECM)
  daysInMilk: number; // DIM (New: Required for NASEM 2021 DMI)
  pregnancyMonth: number; // 0-9
  growthRate: number; // kg/day (heifers)
  bcsChange: number; // -1 to +1 (loss/gain)
  lactationStage: 'early' | 'mid' | 'late';
  environment: 'neutral' | 'heat_mild' | 'heat_severe' | 'cold';
  grazing: 'none' | 'flat' | 'hilly';
  // New Factors
  lactationNumber: number; // 1 (First calf), 2, or 3+ (Mature)
  breed: 'holstein' | 'jersey' | 'other';
}

export interface Nutrients {
  me: number; // Metabolizable Energy (Mcal)
  cp: number; // Crude Protein (g)
  ca: number; // Calcium (g)
  p: number; // Phosphorus (g)
  starch: number; // % DM (displayed) or g (calculated)
  sugar: number; // % DM or g
  ndf: number; // Neutral Detergent Fiber (g)
  adf: number; // Acid Detergent Fiber (g)
  predictedDmi?: number; // NASEM 2021 Predicted Dry Matter Intake (kg)
}

export interface FeedIngredient {
  id: string;
  name: string;
  type: 'concentrate' | 'forage';
  dm: number; // Dry Matter %
  me: number; // Mcal/kg DM
  cp: number; // % DM
  ca: number; // % DM
  p: number; // % DM
  starch: number; // % DM
  sugar: number; // % DM
  ndf: number; // % DM
  adf: number; // % DM
  defaultPrice: number; // Price per kg
}

export interface RationItem {
  ingredientId: string;
  amount: number; // kg as fed
  isPercentage?: boolean; // For concentrate mix definition
}

export interface ConcentrateMix {
  ingredients: RationItem[];
  totalMixAmountFed: number; // kg fed to cow
}

export interface ForageRation {
  ingredients: RationItem[];
}

export enum Page {
  NEEDS = 'NEEDS',
  FEED = 'FEED',
  COMPARE = 'COMPARE',
  HEALTH = 'HEALTH'
}

import { CowParameters, Nutrients, RationItem, FeedIngredient } from '../types';

export const calculateRequirements = (params: CowParameters): Nutrients => {
  let me = 0;
  let cp = 0;
  let ca = 0;
  let p = 0;

  const w075 = Math.pow(params.weight, 0.75);

  // 1. Maintenance (NASEM 2021 Adaptation)
  // Base coefficient for Holstein is ~0.14 Mcal ME/kg BW^0.75 (converted from NEl)
  let meMaintCoeff = 0.14; 

  // Breed Adjustment: Jersey cows have significantly higher basal metabolism
  if (params.breed === 'jersey') {
    meMaintCoeff *= 1.15; // +15% for Jerseys
  }

  // Environment adjustment for Maintenance
  if (params.environment === 'heat_mild') {
    meMaintCoeff *= 1.10; 
  } else if (params.environment === 'heat_severe') {
    meMaintCoeff *= 1.25; 
  } else if (params.environment === 'cold') {
    meMaintCoeff *= 1.15; 
  }

  let activityFactor = 1.0;
  if (params.grazing === 'flat') {
    activityFactor = 1.15;
  } else if (params.grazing === 'hilly') {
    activityFactor = 1.30;
  }

  const meMaint = (meMaintCoeff * w075) * activityFactor;
  const cpMaint = (4.1 * w075) * activityFactor; 

  const caMaint = 0.0154 * params.weight;
  const pMaint = 0.0125 * params.weight;

  me += meMaint;
  cp += cpMaint;
  ca += caMaint;
  p += pMaint;

  // 2. Milk Production
  const nelPerKgMilk = 0.36 + (0.096 * params.fatPercentage);
  const mePerKgMilk = nelPerKgMilk / 0.64; 
  me += params.milkProduction * mePerKgMilk;

  cp += params.milkProduction * 90; 
  ca += params.milkProduction * 1.22;
  p += params.milkProduction * 0.9;

  // 3. Pregnancy
  if (params.pregnancyMonth > 6) {
    const pregFactor = (params.pregnancyMonth - 6);
    me += 1.8 * pregFactor; 
    cp += 110 * pregFactor;
    ca += 10 * pregFactor;
    p += 6 * pregFactor;
  }

  // 4. Growth
  // NASEM encourages adding growth requirements for Parity 1 & 2 even if user didn't specify rate
  let growthRateToUse = params.growthRate;
  if (growthRateToUse === 0) {
      if (params.lactationNumber === 1) growthRateToUse = 0.5; // Auto-add growth for 1st lactation
      if (params.lactationNumber === 2) growthRateToUse = 0.2; // Auto-add growth for 2nd lactation
  }

  if (growthRateToUse > 0) {
     me += 5 * growthRateToUse; 
     cp += 300 * growthRateToUse;
     ca += 25 * growthRateToUse;
     p += 15 * growthRateToUse;
  }

  // 5. Body Condition Change
  if (params.bcsChange > 0) {
      me += 6.0 * params.bcsChange; 
      cp += 60 * params.bcsChange; 
  } else if (params.bcsChange < 0) {
      me += 4.9 * params.bcsChange; 
  }

  // --- NASEM 2021 Dry Matter Intake (DMI) Calculation ---
  // Formula: DMI (kg/d) = [3.7 + 0.012 BW + 0.285 ECM] * (1 - e^(-0.192 * (WOL + 3.67)))
  // First, calculate Energy Corrected Milk (ECM)
  // ECM = (0.327 * Milk) + (12.95 * Fat) + (7.2 * Protein)

  const milkKg = params.milkProduction;
  const fatKg = milkKg * (params.fatPercentage / 100);
  const proteinKg = milkKg * (params.proteinPercentage / 100);

  const ecm = (0.327 * milkKg) + (12.95 * fatKg) + (7.2 * proteinKg);

  // Week of Lactation (WOL)
  const wol = params.daysInMilk / 7;

  // Base DMI (Holsteins) - Simplified NASEM 2021 Structure
  let predictedDmi = 3.75 + (0.012 * params.weight) + (0.285 * ecm);

  // Parity Adjustment for DMI
  // Primiparous cows (Parity 1) have lower DMI capacity due to smaller body frame/gut
  if (params.lactationNumber === 1) {
      predictedDmi = predictedDmi * 0.94; // Roughly 6% reduction for primiparous
  }

  // Early Lactation Lag Adjustment
  const lagFactor = 1 - Math.exp(-0.192 * (wol + 3.67));
  predictedDmi = predictedDmi * lagFactor;

  // Environmental Adjustment for DMI
  // Heat stress reduces DMI, Cold stress may increase (but restricted by gut fill)
  if (params.environment === 'heat_mild') predictedDmi *= 0.92;
  if (params.environment === 'heat_severe') predictedDmi *= 0.85;

  // Use the Predicted DMI to calculate Fiber/Starch constraints
  const estimatedDMI = predictedDmi;

  // Guidelines (approximate):
  // Min NDF: 30% of DM
  // Min ADF: 21% of DM
  // Max Starch: 25-28% of DM
  // Sugar: ~5% (Guideline)

  const ndfReq = estimatedDMI * 1000 * 0.30; // in grams
  const adfReq = estimatedDMI * 1000 * 0.21; // in grams
  const starchMax = estimatedDMI * 1000 * 0.26; // in grams (Max limit)
  const sugarReq = estimatedDMI * 1000 * 0.05; // in grams (Rough target)

  return {
    me: parseFloat(me.toFixed(2)),
    cp: Math.round(cp),
    ca: Math.round(ca),
    p: Math.round(p),
    ndf: Math.round(ndfReq),
    adf: Math.round(adfReq),
    starch: Math.round(starchMax), 
    sugar: Math.round(sugarReq),
    predictedDmi: parseFloat(estimatedDMI.toFixed(1))
  };
};

export const calculateSupplied = (
  concentrateMix: RationItem[], 
  concentrateAmountFed: number, 
  forages: RationItem[],
  feedDatabase: FeedIngredient[] 
): Nutrients & { totalDM: number, concentrateAnalysis: Nutrients } => {

  let totalME = 0;
  let totalCP = 0;
  let totalCa = 0;
  let totalP = 0;
  let totalStarch = 0;
  let totalSugar = 0;
  let totalNDF = 0;
  let totalADF = 0;
  let totalDM = 0;

  // 1. Calculate Concentrate Mix Analysis (per 1kg of mix)
  const totalParts = concentrateMix.reduce((acc, item) => acc + item.amount, 0);

  let mixME = 0, mixCP = 0, mixCa = 0, mixP = 0, mixStarch = 0, mixSugar = 0, mixNDF = 0, mixADF = 0;

  if (totalParts > 0) {
    concentrateMix.forEach(item => {
        const feed = feedDatabase.find(f => f.id === item.ingredientId);
        if (feed) {
            const ratio = item.amount / totalParts; 
            const dmFactor = feed.dm / 100;

            mixME += (feed.me * dmFactor) * ratio;
            mixCP += (feed.cp * 10 * dmFactor) * ratio;
            mixCa += (feed.ca * 10 * dmFactor) * ratio;
            mixP += (feed.p * 10 * dmFactor) * ratio;
            mixStarch += (feed.starch * 10 * dmFactor) * ratio;
            mixSugar += (feed.sugar * 10 * dmFactor) * ratio;
            mixNDF += (feed.ndf * 10 * dmFactor) * ratio;
            mixADF += (feed.adf * 10 * dmFactor) * ratio;
        }
    });
  }

  const concAnalysis = { me: mixME, cp: mixCP, ca: mixCa, p: mixP, starch: mixStarch, sugar: mixSugar, ndf: mixNDF, adf: mixADF };

  // 2. Add Concentrate Supplied to Total
  totalME += mixME * concentrateAmountFed;
  totalCP += mixCP * concentrateAmountFed;
  totalCa += mixCa * concentrateAmountFed;
  totalP += mixP * concentrateAmountFed;
  totalStarch += mixStarch * concentrateAmountFed;
  totalSugar += mixSugar * concentrateAmountFed;
  totalNDF += mixNDF * concentrateAmountFed;
  totalADF += mixADF * concentrateAmountFed;

  const mixDM = concentrateMix.reduce((acc, item) => {
      const feed = feedDatabase.find(f => f.id === item.ingredientId);
      return acc + (feed ? (feed.dm / 100) * (item.amount/totalParts) : 0);
  }, 0);
  totalDM += mixDM * concentrateAmountFed;

  // 3. Add Forages
  forages.forEach(item => {
      const feed = feedDatabase.find(f => f.id === item.ingredientId);
      if (feed && item.amount > 0) {
          const dmFactor = feed.dm / 100;
          const kgDM = item.amount * dmFactor;

          totalME += feed.me * kgDM;
          totalCP += feed.cp * 10 * kgDM;
          totalCa += feed.ca * 10 * kgDM;
          totalP += feed.p * 10 * kgDM;

          // Add new nutrients
          totalStarch += feed.starch * 10 * kgDM;
          totalSugar += feed.sugar * 10 * kgDM;
          totalNDF += feed.ndf * 10 * kgDM;
          totalADF += feed.adf * 10 * kgDM;

          totalDM += kgDM;
      }
  });

  return {
    me: parseFloat(totalME.toFixed(2)),
    cp: Math.round(totalCP),
    ca: Math.round(totalCa),
    p: Math.round(totalP),
    starch: Math.round(totalStarch),
    sugar: Math.round(totalSugar),
    ndf: Math.round(totalNDF),
    adf: Math.round(totalADF),
    totalDM: parseFloat(totalDM.toFixed(2)),
    concentrateAnalysis: {
        me: parseFloat(mixME.toFixed(2)),
        cp: Math.round(mixCP),
        ca: Math.round(mixCa),
        p: Math.round(mixP),
        starch: Math.round(mixStarch),
        sugar: Math.round(mixSugar),
        ndf: Math.round(mixNDF),
        adf: Math.round(mixADF)
    }
  };
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import NeedsForm from './components/NeedsForm';
import FeedForm from './components/FeedForm';
import Comparison from './components/Comparison';
import HealthAdvisor from './components/HealthAdvisor';
import { CowParameters, Nutrients, RationItem, Page, FeedIngredient } from './types';
import { calculateRequirements, calculateSupplied } from './services/calculator';
import { FEED_DATABASE } from './constants';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<Page>(Page.NEEDS);

  // State: Cow Parameters
  const initialCowParams: CowParameters = {
    weight: 600,
    milkProduction: 25,
    fatPercentage: 3.8,
    proteinPercentage: 3.2,
    daysInMilk: 150, 
    pregnancyMonth: 0,
    growthRate: 0,
    bcsChange: 0,
    lactationStage: 'mid',
    environment: 'neutral',
    grazing: 'none',
    // New Defaults
    lactationNumber: 3, // Mature by default
    breed: 'holstein'
  };
  const [cowParams, setCowParams] = useState<CowParameters>(initialCowParams);

  // State: Requirements (Calculated)
  // Initialized with all properties to avoid runtime/type errors
  const [needs, setNeeds] = useState<Nutrients>({ 
    me: 0, cp: 0, ca: 0, p: 0, 
    starch: 0, sugar: 0, ndf: 0, adf: 0,
    predictedDmi: 0
  });

  // State: Ingredients (Initialized from constant, but mutable)
  const [ingredients, setIngredients] = useState<FeedIngredient[]>(FEED_DATABASE);

  // State: Feed
  const [concentrateMix, setConcentrateMix] = useState<RationItem[]>([]);
  const [concentrateFedAmount, setConcentrateFedAmount] = useState<number>(0);
  const [forages, setForages] = useState<RationItem[]>([]);

  // State: Supplied (Calculated)
  const [supplied, setSupplied] = useState<Nutrients>({ 
    me: 0, cp: 0, ca: 0, p: 0,
    starch: 0, sugar: 0, ndf: 0, adf: 0
  });
  const [totalDM, setTotalDM] = useState<number>(0);
  const [mixAnalysis, setMixAnalysis] = useState<Nutrients>({ 
    me: 0, cp: 0, ca: 0, p: 0,
    starch: 0, sugar: 0, ndf: 0, adf: 0
  });

  // State: Cost
  const [totalCost, setTotalCost] = useState<number>(0);

  const handleReset = () => {
    if (window.confirm("هل أنت متأكد من رغبتك في بدء جلسة جديدة؟ سيتم مسح جميع المدخلات.")) {
        setCowParams(initialCowParams);
        setConcentrateMix([]);
        setConcentrateFedAmount(0);
        setForages([]);
        setIngredients(FEED_DATABASE);
        setActivePage(Page.NEEDS);
        window.scrollTo(0, 0);
    }
  };

  // Effects to trigger calculations
  useEffect(() => {
    const calculated = calculateRequirements(cowParams);
    setNeeds(calculated);
  }, [cowParams]);

  useEffect(() => {
    const result = calculateSupplied(concentrateMix, concentrateFedAmount, forages, ingredients);
    setSupplied(result);
    setTotalDM(result.totalDM);
    setMixAnalysis(result.concentrateAnalysis);

    // Calculate Costs
    // 1. Concentrate Mix Cost per kg
    const totalMixWeight = concentrateMix.reduce((sum, item) => sum + item.amount, 0);
    let mixPricePerKg = 0;
    if (totalMixWeight > 0) {
        const totalMixCost = concentrateMix.reduce((sum, item) => {
            const ing = ingredients.find(i => i.id === item.ingredientId);
            return sum + (item.amount * (ing?.defaultPrice || 0));
        }, 0);
        mixPricePerKg = totalMixCost / totalMixWeight;
    }

    // 2. Total Daily Cost
    let dailyCost = 0;
    // Cost of concentrate fed
    dailyCost += mixPricePerKg * concentrateFedAmount;
    // Cost of forages
    forages.forEach(f => {
        const ing = ingredients.find(i => i.id === f.ingredientId);
        dailyCost += f.amount * (ing?.defaultPrice || 0);
    });

    setTotalCost(dailyCost);

  }, [concentrateMix, concentrateFedAmount, forages, ingredients]);

  // Rough estimation of total forage amount for AI context
  const totalForageAmount = forages.reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <Layout activePage={activePage} setPage={setActivePage} onReset={handleReset}>
      {activePage === Page.NEEDS && (
        <NeedsForm 
            params={cowParams} 
            setParams={setCowParams} 
            calculatedNeeds={needs} 
        />
      )}

      {activePage === Page.FEED && (
        <FeedForm 
            concentrateMix={concentrateMix}
            setConcentrateMix={setConcentrateMix}
            concentrateFedAmount={concentrateFedAmount}
            setConcentrateFedAmount={setConcentrateFedAmount}
            forages={forages}
            setForages={setForages}
            mixAnalysis={mixAnalysis}
            ingredients={ingredients}
            setIngredients={setIngredients}
        />
      )}

      {activePage === Page.COMPARE && (
        <Comparison 
            needs={needs}
            supplied={supplied}
            totalDM={totalDM}
            totalCost={totalCost}
            milkProduction={cowParams.milkProduction}
        />
      )}

      {activePage === Page.HEALTH && (
        <HealthAdvisor 
            params={cowParams}
            needs={needs}
            supplied={supplied}
            concentrateAmount={concentrateFedAmount}
            forageAmount={totalForageAmount}
        />
      )}
    </Layout>
  );
};

export default App;

